1	export type Cell = [number, number];
2	
3	const MIN_NEIGHBORS_TO_SURVIVE = 2;
4	const MAX_NEIGHBORS_TO_SURVIVE = 3;
5	const NEIGHBORS_TO_REPRODUCE = 3;
6	
7	function isNeighbor(a: Cell, b: Cell): boolean {
8	  const [ax, ay] = a;
9	  const [bx, by] = b;
10	  return Math.max(Math.abs(ax - bx), Math.abs(ay - by)) === 1;
11	}
12	
13	function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
14	  return cells.filter((other) => isNeighbor(cell, other)).length;
15	}
16	
17	function isAlive(cell: Cell, cells: Cell[]): boolean {
18	  const [x, y] = cell;
19	  return cells.some(([cx, cy]) => cx === x && cy === y);
20	}
21	
22	const NEIGHBORHOOD_OFFSETS: Cell[] = [
23	  [-1, -1], [0, -1], [1, -1],
24	  [-1, 0], [0, 0], [1, 0],
25	  [-1, 1], [0, 1], [1, 1],
26	];
27	
28	function cellWithNeighbors([x, y]: Cell): Cell[] {
29	  return NEIGHBORHOOD_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
30	}
31	
32	function cellKey([x, y]: Cell): string {
33	  return `${x},${y}`;
34	}
35	
36	function candidateCells(cells: Cell[]): Cell[] {
37	  const all = cells.flatMap(cellWithNeighbors);
38	  return [...new Map(all.map((cell) => [cellKey(cell), cell])).values()];
39	}
40	
41	function livesNextGeneration(cell: Cell, cells: Cell[]): boolean {
42	  const count = countLiveNeighbors(cell, cells);
43	  if (isAlive(cell, cells)) {
44	    return count >= MIN_NEIGHBORS_TO_SURVIVE && count <= MAX_NEIGHBORS_TO_SURVIVE;
45	  }
46	  return count === NEIGHBORS_TO_REPRODUCE;
47	}
48	
49	export function nextGeneration(cells: Cell[]): Cell[] {
50	  return candidateCells(cells).filter((cell) => livesNextGeneration(cell, cells));
51	}
