1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty input returns empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 2 neighbors survives (rule 2 survival)", () => {
15	    // Horizontal row: (0,0), (1,0), (2,0). Middle cell (1,0) has 2 live neighbors → survives.
16	    const next = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(next).toContainEqual([1, 0]);
18	  });
19	  it("live cell with 3 neighbors survives (rule 2 survival) — block cell survives", () => {
20	    // Block: each cell has exactly 3 live neighbors → all survive
21	    const next = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
22	    expect(next).toContainEqual([0, 0]);
23	  });
24	  it("live cell with 4 neighbors dies (overpopulation)", () => {
25	    // Center (1,1) has 4 diagonal live neighbors: (0,0), (2,0), (0,2), (2,2)
26	    const next = nextGeneration([[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]]);
27	    expect(next).not.toContainEqual([1, 1]);
28	  });
29	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction)", () => {
30	    // Dead cell (1,1) has live neighbors (0,0), (1,0), (0,1) — exactly 3 → born
31	    const next = nextGeneration([[0, 0], [1, 0], [0, 1]]);
32	    expect(next).toContainEqual([1, 1]);
33	  });
34	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
35	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const next = nextGeneration(block);
37	    expect(next).toHaveLength(4);
38	    for (const cell of block) expect(next).toContainEqual(cell);
39	  });
40	  it("vertical blinker becomes horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
41	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
42	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
43	    expect(next).toHaveLength(3);
44	    for (const cell of expected) expect(next).toContainEqual(cell);
45	  });
46	  it.todo("handles negative coordinates correctly");
47	});
